-- [5] SOCIO: ALVAREZ CAMPOS ROLANDO (Puesto: 170, ID: 5)
DO $b5$
DECLARE
    v_user_uuid         uuid;
    v_pago_res          json;
    v_pago_id           bigint;
    v_socio_5 bigint := 5;
    v_puesto_5 bigint := 170;
    v_m_id_5_0 bigint;
    v_m_id_5_1 bigint;
    v_m_id_5_2 bigint;
    v_m_id_5_3 bigint;
    v_m_id_5_4 bigint;
    v_m_id_5_5 bigint;
    v_m_id_5_6 bigint;
    v_m_id_5_7 bigint;
    v_m_id_5_8 bigint;
    v_m_id_5_9 bigint;
    v_m_id_5_10 bigint;
    v_m_id_5_11 bigint;
    v_m_id_5_12 bigint;
    v_m_id_5_13 bigint;
    v_m_id_5_14 bigint;
    v_m_id_5_15 bigint;
    v_m_id_5_16 bigint;
    v_m_id_5_17 bigint;
    v_m_id_5_18 bigint;
    v_m_id_5_19 bigint;
    v_m_id_5_20 bigint;
    v_m_id_5_21 bigint;
    v_m_id_5_22 bigint;
    v_m_id_5_23 bigint;
BEGIN
    -- Obtener un UUID de usuario administrador para auditoría
    SELECT id INTO v_user_uuid FROM public.perfiles WHERE rol = 'Administrador' AND activo = true LIMIT 1;
    IF v_user_uuid IS NULL THEN v_user_uuid := '00000000-0000-0000-0000-000000000000'; END IF;
    PERFORM set_config('request.jwt.claims', json_build_object('sub', v_user_uuid::text, 'role', 'authenticated')::text, true);

    -- 1. Limpiar datos previos de este puesto para evitar duplicados
    DELETE FROM public.detalle_pagos WHERE monto_id IN (
        SELECT id FROM public.montos_por_cobrar 
        WHERE puesto_id = v_puesto_5 
          AND (observacion LIKE 'Migración de deudas 2026 - %' OR observacion LIKE 'Migración de pagos 2026 - %')
    );
    DELETE FROM public.pagos WHERE puesto_id = v_puesto_5 
      AND (observacion LIKE 'Pago histórico%' OR observacion LIKE 'Pago mensual vía tarjeta - %' OR observacion LIKE 'Pago mensual vía banco - %' OR observacion LIKE 'Pago histórico recibo N° %');
    DELETE FROM public.montos_por_cobrar WHERE puesto_id = v_puesto_5 
