-- [────────────────────────────────────────────────────────]
-- [91] SOCIO: MAYTA MATOS HERMELINDA (Puesto: 184, ID: 94)
DO $b91$
DECLARE
    v_user_uuid         uuid;
    v_pago_res          json;
    v_pago_id           bigint;
    v_socio_94 bigint := 94;
    v_puesto_94 bigint := 184;
    v_m_id_94_0 bigint;
    v_m_id_94_1 bigint;
    v_m_id_94_2 bigint;
    v_m_id_94_3 bigint;
    v_m_id_94_4 bigint;
    v_m_id_94_5 bigint;
    v_m_id_94_6 bigint;
    v_m_id_94_7 bigint;
    v_m_id_94_8 bigint;
    v_m_id_94_9 bigint;
    v_m_id_94_10 bigint;
    v_m_id_94_11 bigint;
    v_m_id_94_12 bigint;
    v_m_id_94_13 bigint;
    v_m_id_94_14 bigint;
    v_m_id_94_15 bigint;
    v_m_id_94_16 bigint;
    v_m_id_94_17 bigint;
    v_m_id_94_18 bigint;
    v_m_id_94_19 bigint;
    v_m_id_94_20 bigint;
    v_m_id_94_21 bigint;
    v_m_id_94_22 bigint;
    v_m_id_94_23 bigint;
    v_m_id_94_24 bigint;
BEGIN
    -- Obtener un UUID de usuario administrador para auditoría
    SELECT id INTO v_user_uuid FROM public.perfiles WHERE rol = 'Administrador' AND activo = true LIMIT 1;
    IF v_user_uuid IS NULL THEN v_user_uuid := '00000000-0000-0000-0000-000000000000'; END IF;
    PERFORM set_config('request.jwt.claims', json_build_object('sub', v_user_uuid::text, 'role', 'authenticated')::text, true);

    -- 1. Limpiar datos previos de este puesto para evitar duplicados
    DELETE FROM public.detalle_pagos WHERE monto_id IN (
        SELECT id FROM public.montos_por_cobrar 
        WHERE puesto_id = v_puesto_94 
          AND (observacion LIKE 'Migración de deudas 2026 - %' OR observacion LIKE 'Migración de pagos 2026 - %')
    );
    DELETE FROM public.pagos WHERE puesto_id = v_puesto_94 
      AND (observacion LIKE 'Pago histórico%' OR observacion LIKE 'Pago mensual vía tarjeta - %' OR observacion LIKE 'Pago mensual vía banco - %' OR observacion LIKE 'Pago histórico recibo N° %');
    DELETE FROM public.montos_por_cobrar WHERE puesto_id = v_puesto_94 
      AND (observacion LIKE 'Migración de deudas 2026 - %' OR observacion LIKE 'Migración de pagos 2026 - %');
