-- [99] SOCIO: MEDINA MEDRANO JUAN CARLOS (Puesto: 238, ID: 97)
DO $b99$
DECLARE
    v_user_uuid         uuid;
    v_pago_res          json;
    v_pago_id           bigint;
    v_socio_97 bigint := 97;
    v_puesto_97 bigint := 238;
    v_m_id_97_0 bigint;
    v_m_id_97_1 bigint;
    v_m_id_97_2 bigint;
    v_m_id_97_3 bigint;
    v_m_id_97_4 bigint;
    v_m_id_97_5 bigint;
