-- [107] SOCIO: ORTIZ NAUPA WELINTONH (Puesto: 279, ID: 108)
DO $b107$
DECLARE
    v_user_uuid         uuid;
    v_pago_res          json;
    v_pago_id           bigint;
    v_socio_108 bigint := 108;
    v_puesto_108 bigint := 279;
    v_m_id_108_0 bigint;
    v_m_id_108_1 bigint;
    v_m_id_108_2 bigint;
    v_m_id_108_3 bigint;
    v_m_id_108_4 bigint;
    v_m_id_108_5 bigint;
    v_m_id_108_6 bigint;
    v_m_id_108_7 bigint;
    v_m_id_108_8 bigint;
    v_m_id_108_9 bigint;
    v_m_id_108_10 bigint;
    v_m_id_108_11 bigint;
    v_m_id_108_12 bigint;
    v_m_id_108_13 bigint;
    v_m_id_108_14 bigint;
    v_m_id_108_15 bigint;
    v_m_id_108_16 bigint;
    v_m_id_108_17 bigint;
    v_m_id_108_18 bigint;
    v_m_id_108_19 bigint;
    v_m_id_108_20 bigint;
    v_m_id_108_21 bigint;
    v_m_id_108_22 bigint;
    v_m_id_108_23 bigint;
BEGIN
    -- Obtener un UUID de usuario administrador para auditoría
    SELECT id INTO v_user_uuid FROM public.perfiles WHERE rol = 'Administrador' AND activo = true LIMIT 1;
    IF v_user_uuid IS NULL THEN v_user_uuid := '00000000-0000-0000-0000-000000000000'; END IF;
    PERFORM set_config('request.jwt.claims', json_build_object('sub', v_user_uuid::text, 'role', 'authenticated')::text, true);

    -- 1. Limpiar datos previos de este puesto para evitar duplicados
    DELETE FROM public.detalle_pagos WHERE monto_id IN (
        SELECT id FROM public.montos_por_cobrar 
        WHERE puesto_id = v_puesto_108 
          AND (observacion LIKE 'Migración de deudas 2026 - %' OR observacion LIKE 'Migración de pagos 2026 - %')
    );
    DELETE FROM public.pagos WHERE puesto_id = v_puesto_108 
      AND (observacion LIKE 'Pago histórico%' OR observacion LIKE 'Pago mensual vía tarjeta - %' OR observacion LIKE 'Pago mensual vía banco - %' OR observacion LIKE 'Pago histórico recibo N° %');
    DELETE FROM public.montos_por_cobrar WHERE puesto_id = v_puesto_108 
      AND (observacion LIKE 'Migración de deudas 2026 - %' OR observacion LIKE 'Migración de pagos 2026 - %');
    UPDATE public.socios SET saldo_a_favor = 0.00 WHERE id = v_socio_108;

    -- 2. Insertar deudas agrupadas
    INSERT INTO public.montos_por_cobrar (puesto_id, concepto_id, periodo_anio, periodo_mes, monto, estado, metodo_calculo, fecha_generacion, observacion, created_by)
    VALUES (v_puesto_108, 1, 2025, 11, 133.10, 'Pendiente', 'Manual', '2025-11-01', 'Migración de deudas 2026 - LUZ', v_user_uuid)
    RETURNING id INTO v_m_id_108_0;
    INSERT INTO public.montos_por_cobrar (puesto_id, concepto_id, periodo_anio, periodo_mes, monto, estado, metodo_calculo, fecha_generacion, observacion, created_by)
    VALUES (v_puesto_108, 2, 2025, 11, 8.70, 'Pendiente', 'Manual', '2025-11-01', 'Migración de deudas 2026 - AGUA', v_user_uuid)
