-- [108] SOCIO: PACOMPIA CARDENA GIOVANNI (Puesto: 94, ID: 109)
DO $b108$
DECLARE
    v_user_uuid         uuid;
    v_pago_res          json;
    v_pago_id           bigint;
    v_socio_109 bigint := 109;
    v_puesto_109 bigint := 94;
    v_m_id_109_0 bigint;
    v_m_id_109_1 bigint;
    v_m_id_109_2 bigint;
    v_m_id_109_3 bigint;
    v_m_id_109_4 bigint;
    v_m_id_109_5 bigint;
    v_m_id_109_6 bigint;
    v_m_id_109_7 bigint;
    v_m_id_109_8 bigint;
    v_m_id_109_9 bigint;
    v_m_id_109_10 bigint;
    v_m_id_109_11 bigint;
