    SELECT id INTO v_user_uuid FROM public.perfiles WHERE rol = 'Administrador' AND activo = true LIMIT 1;
    IF v_user_uuid IS NULL THEN v_user_uuid := '00000000-0000-0000-0000-000000000000'; END IF;
    PERFORM set_config('request.jwt.claims', json_build_object('sub', v_user_uuid::text, 'role', 'authenticated')::text, true);

    -- 1. Limpiar datos previos de este puesto para evitar duplicados
    DELETE FROM public.detalle_pagos WHERE monto_id IN (
        SELECT id FROM public.montos_por_cobrar 
        WHERE puesto_id = v_puesto_146 
          AND (observacion LIKE 'Migración de deudas 2026 - %' OR observacion LIKE 'Migración de pagos 2026 - %')
    );
    DELETE FROM public.pagos WHERE puesto_id = v_puesto_146 
